using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_TooFewDigits_ThrowsArgumentException()
    {
        _formatter.FormatPhoneNumber("12345");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_TooManyDigits_ThrowsArgumentException()
    {
        _formatter.FormatPhoneNumber("12345678901");
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsGreetingWithMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_Result_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Doe");

        StringAssert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_Result_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_Result_ContainsName()
    {
        var result = _formatter.BuildGreeting("Anderson");

        StringAssert.Contains(result, "Anderson");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        _formatter.BuildGreeting("   ");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_EmptyName_ThrowsArgumentException()
    {
        _formatter.BuildGreeting("");
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_ReplacedWithDashes()
    {
        var result = _formatter.GenerateSlug("C# is Great!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_AreTrimmed()
    {
        var result = _formatter.GenerateSlug("  some title  ");

        Assert.AreEqual("some-title", result);
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpaces_CollapsedToSingleDash()
    {
        var result = _formatter.GenerateSlug("one   two   three");

        Assert.AreEqual("one-two-three", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("--leading");

        Assert.AreNotEqual('-', result[0]);
    }

    [TestMethod]
    public void GenerateSlug_Result_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("trailing--");

        StringAssert.EndsWith(result, "trailing");
        Assert.AreNotEqual('-', result[^1]);
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_ReturnsAllLowercase()
    {
        var result = _formatter.GenerateSlug("My UPPER Title");

        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^[a-z0-9\-]+$"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceOnly_ThrowsArgumentException()
    {
        _formatter.GenerateSlug("   ");
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(9.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWith00()
    {
        var result = _formatter.FormatCurrency(50m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_FormattedCorrectly()
    {
        var result = _formatter.FormatCurrency(9.5m);

        Assert.AreEqual("$9.50", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-25.00m);

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_ReturnsSymbolAndZero()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }

    [TestMethod]
    public void FormatCurrency_LargeAmount_FormattedCorrectly()
    {
        var result = _formatter.FormatCurrency(1234567.89m, "£");

        StringAssert.StartsWith(result, "£");
        StringAssert.EndsWith(result, ".89");
    }
}

